// ── COMPLIANCE AWARENESS INJECTION ──────────────────────────────────────
// Injects relevant compliance frameworks into prompts when the seller or
// target operates in a regulated vertical. Uses KL_COMPLIANCE data.
const COMPLIANCE_VERTICAL_KW = {
  fintech_payments: ["fintech", "payment processing", "banking", "financial services", "lending", "neobank", "processor", "acquiring", "interchange", "payfac"],
  digital_rewards_incentives: ["incentive program", "reward platform", "gift card", "employee recognition", "loyalty program", "stored-value"],
  health_wellness_b2b: ["healthcare", "wellness platform", "clinical", "hipaa", "health system", "medical device", "patient engagement", "pharma", "telehealth"],
  market_research: ["market research", "survey platform", "panel provider", "respondent"],
  real_estate: ["real estate", "homebuilder", "property developer", "land wholesaling", "reit", "btr", "build-to-rent"],
  cybersecurity: ["cybersecurity", "infosec", "soc 2", "siem", "edr", "xdr", "zero trust", "ransomware", "fedramp"],
  manufacturing: ["manufacturing", "factory", "oem", "automotive", "aerospace", "fda regulated"],
  government: ["government", "federal agency", "state government", "public sector", "govtech", "defense", "dod", "fedramp", "fisma"],
  saas_martech: ["saas platform", "software as a service", "martech", "marketing technology", "b2b software", "cloud software"],
  education: ["education", "edtech", "k-12", "higher education", "university", "school district", "lms"],
};
function getComplianceInjection(sellerICP, targetIndustry) {
  if (!KL_COMPLIANCE?.frameworks?.length) return "";
  const text = [sellerICP?.marketCategory, sellerICP?.sellerDescription, ...(sellerICP?.icp?.industries || []), targetIndustry].filter(Boolean).join(" ").toLowerCase();
  if (!text) return "";
  // Match verticals
  const matchedVerts = [];
  for (const [vId, kws] of Object.entries(COMPLIANCE_VERTICAL_KW)) {
    if (kws.some(kw => text.includes(kw))) matchedVerts.push(vId);
  }
  if (!matchedVerts.length) return "";
  // Collect primary frameworks from matched verticals
  const vMap = KL_COMPLIANCE.verticalMap || {};
  const seen = new Set();
  const frameworks = [];
  for (const vId of matchedVerts) {
    for (const fId of (vMap[vId]?.primary_frameworks || [])) {
      if (!seen.has(fId)) {
        seen.add(fId);
        const f = KL_COMPLIANCE.frameworks.find(x => x.id === fId);
        if (f) frameworks.push(f);
      }
    }
  }
  if (!frameworks.length) return "";
  const parts = ["\nCOMPLIANCE LANDSCAPE AWARENESS (Cambrian Catalyst does NOT provide compliance services — we help sellers understand the regulatory landscape their buyers operate in):"];
  for (const f of frameworks.slice(0, 5)) {
    const summary = f.talking_points?.what_reps_should_know || f.summary || "";
    parts.push(`- ${f.name}: ${summary.split(".").slice(0, 2).join(".")}.`);
  }
  parts.push("IMPORTANT: Cambrian Catalyst is a GTM consultancy, not a compliance provider. We help sellers understand and navigate compliance topics in sales conversations — not implement, audit, or certify compliance programs. Always escalate to the prospect's compliance team or qualified counsel for program design, audit scope, or legal interpretation.");
  return parts.join("\n") + "\n";
}

function getComplianceDiscovery(sellerICP, targetIndustry) {
  if (!KL_COMPLIANCE?.frameworks?.length) return "";
  const text = [sellerICP?.marketCategory, sellerICP?.sellerDescription, ...(sellerICP?.icp?.industries || []), targetIndustry].filter(Boolean).join(" ").toLowerCase();
  if (!text) return "";
  const matchedVerts = [];
  for (const [vId, kws] of Object.entries(COMPLIANCE_VERTICAL_KW)) {
    if (kws.some(kw => text.includes(kw))) matchedVerts.push(vId);
  }
  if (!matchedVerts.length) return "";
  const vMap = KL_COMPLIANCE.verticalMap || {};
  const seen = new Set();
  const qs = [];
  for (const vId of matchedVerts) {
    for (const fId of (vMap[vId]?.primary_frameworks || [])) {
      if (!seen.has(fId)) {
        seen.add(fId);
        const f = KL_COMPLIANCE.frameworks.find(x => x.id === fId);
        if (f?.discovery_questions?.length) qs.push(`${f.name}: ${f.discovery_questions[0]}`);
      }
    }
  }
  if (!qs.length) return "";
  return `\nCOMPLIANCE DISCOVERY (ask when relevant):\n${qs.slice(0, 4).map(q => `- ${q}`).join("\n")}\n`;
}

