// ── PLAIN AI CALL — JSON synthesis from research ──────────────────────────────

// Shared retry wrapper for non-streaming Claude calls. Handles transient
// Anthropic errors:
//   - overloaded_error / HTTP 529 (Anthropic capacity)  → 2s, 5s, 10s
//   - rate_limit_error / HTTP 429 (per-account limits)  → 15s, 30s, 45s
// Returns the parsed response body. After retries are exhausted, returns
// { error: { type: "unavailable", ... } } so callers can surface a useful
// message instead of a silent null.
async function claudeFetch(body, { retries = 3, extraHeaders = {} } = {}) {
  const sleep = ms => new Promise(r => setTimeout(r, ms));
  for (let attempt = 0; attempt < retries; attempt++) {
    try {
      const r = await fetch("/api/claude", {
        method: "POST",
        headers: { ...authHeaders(), ..._trackingCtx, ...extraHeaders },
        body: JSON.stringify(body),
      });
      // Handle 402 (usage limit) — surface to caller, don't retry
      if (r.status === 402) {
        const d = await r.json();
        window.dispatchEvent(new CustomEvent("usage-limit-exceeded", { detail: d }));
        return d;
      }
      // Log ALL non-200 responses so we can see guard rejections
      if (!r.ok) {
        const errText = await r.clone().text().catch(() => "");
        console.error(`[claudeFetch] HTTP ${r.status} for model=${body.model}:`, errText.slice(0, 500));
      }
      const d = stripCitations(await r.json());
      if (d?.error) {
        const t = d.error.type;
        const isOverload = t === "overloaded_error" || r.status === 529;
        const isRate     = t === "rate_limit_error" || r.status === 429;
        if ((isOverload || isRate) && attempt < retries - 1) {
          const wait = isOverload ? [2000, 5000, 10000][attempt] : 15000 * (attempt + 1);
          console.warn(`[claude] ${t}, retrying in ${wait/1000}s (attempt ${attempt+1}/${retries})`);
          await sleep(wait);
          continue;
        }
        return d; // non-retryable, or out of retries — return for caller to handle
      }
      return d;
    } catch (e) {
      console.warn(`[claude] fetch failed (${attempt+1}/${retries}):`, e.message);
      if (attempt < retries - 1) await sleep(2000 * (attempt + 1));
    }
  }
  return { error: { type: "unavailable", message: "Even the best need a breather. Our AI engine is recharging — try again in a moment." } };
}

// ── UNIVERSAL ANTI-HALLUCINATION GUARD ──────────────────────────────────
// Injected into the system prompt of EVERY AI call (callAI, streamAI,
// streamAIWithSearch). This is the last line of defense — individual
// prompts add domain-specific guards, but this catches everything.
const ANTI_HALLUCINATION_SYSTEM = `You are a JSON API. Output only valid JSON. Use only ASCII punctuation.
ANTI-HALLUCINATION RULES (apply to EVERY response):
- NEVER fabricate statistics, market share figures, revenue numbers, employee counts, or financial metrics. If you do not have verified data, return an empty string.
- NEVER invent person names, executive names, or attribute quotes to people. If you cannot verify a name, describe the role instead.
- NEVER invent company names, customer names, or partnership claims. Only cite companies you are certain exist and are relevant.
- NEVER invent conference names, event dates, or future dates. You do not reliably know the current date or upcoming events.
- NEVER present review-platform metrics (G2 rankings, Capterra product counts, review-site "market share") as actual market share or economic data.
- If data was not provided in the context above or found via web search, return an empty string for that field. Empty is ALWAYS better than fabricated.
- A sales rep who cites a wrong fact in a meeting loses credibility permanently. Your job is to be RIGHT, not to be complete.
- NEVER disparage or undermine the selling organization. You are building tools FOR the seller. Do not editorialize about their product quality, pricing, viability, or market position.`;

async function streamAI(prompt, onChunk, maxTok=2000, { model = null } = {}) {
  const sleep = ms => new Promise(r => setTimeout(r, ms));
  // Wrap the initial fetch in retry. Once the stream is open we let it run
  // through; mid-stream failures surface as a null parse result and the
  // caller already handles that case.
  let response = null;
  for (let attempt = 0; attempt < 3; attempt++) {
    response = await fetch('/api/claude-stream', {
      method: 'POST',
      headers: { ...authHeaders(), ..._trackingCtx },
      body: JSON.stringify({
        model: model || activeModel(),
        max_tokens: maxTok,
        temperature: 0,
        system: ANTI_HALLUCINATION_SYSTEM,
        messages: [
          { role: 'user', content: prompt + '\n\nRespond with ONLY raw JSON starting with {. No prose, no markdown, no explanation.' },
        ],
      }),
    });
    if (response.status !== 529 && response.status !== 429) break;
    const wait = response.status === 529 ? [2000, 5000, 10000][attempt] : 15000;
    console.warn(`[claude-stream] HTTP ${response.status}, retry ${attempt+1}/3 in ${wait/1000}s`);
    await sleep(wait);
  }
  if (!response || !response.body) return null;
  const reader = response.body.getReader();
  const decoder = new TextDecoder();
  let buffer = '';
  let fullText = '';
  while (true) {
    const { done, value } = await reader.read();
    if (done) break;
    buffer += decoder.decode(value, { stream: true });
    const lines = buffer.split('\n');
    buffer = lines.pop();
    for (const line of lines) {
      if (!line.startsWith('data: ')) continue;
      const data = line.slice(6).trim();
      if (data === '[DONE]') continue;
      try {
        const event = JSON.parse(data);
        if (event.type === 'content_block_delta' && event.delta?.text) {
          fullText += event.delta.text;
          onChunk(fullText.replace(/<\/?cite[^>]*>/g, "").replace(/```(?:json)?\s*/gi, "").replace(/```\s*/g, "").replace(/<\/?thinking>/g, ""));
        }
      } catch { /* non-critical */ }
    }
  }
  try {
    let cleaned = fullText.replace(/<\/?cite[^>]*>/g, "").replace(/```(?:json)?\s*/gi, "").replace(/```\s*/g, "").replace(/<\/?thinking>/g, "").trim();
    const fb = cleaned.indexOf("{");
    const lb = cleaned.lastIndexOf("}");
    if (fb >= 0 && lb > fb) cleaned = cleaned.slice(fb, lb + 1);
    return stripCitations(JSON.parse(cleaned));
  } catch { return null; }
}

// streamAIWithSearch: like streamAI but with web_search tool support.
// The model may call web_search before generating JSON. We:
//   - Pass tools in the request body (server already handles this)
//   - Remove the assistant "{" prefill (incompatible with tool use)
//   - Track content block types — only feed TEXT blocks to onChunk
//   - Use extractJsonWithKey for final parse (handles preamble text)
// anchorKey: the expected top-level JSON key to find (e.g. "elevatorPitch")
async function streamAIWithSearch(prompt, onChunk, maxTok=2000, { maxSearches=1, anchorKey=null, onStatus=null, model=null } = {}) {
  const sleep = ms => new Promise(r => setTimeout(r, ms));
  let response = null;
  for (let attempt = 0; attempt < 3; attempt++) {
    response = await fetch('/api/claude-stream', {
      method: 'POST',
      headers: { ...authHeaders(), ..._trackingCtx },
      body: JSON.stringify({
        model: model || activeModel(),
        max_tokens: maxTok,
        temperature: 0,
        system: ANTI_HALLUCINATION_SYSTEM,
        tools: [{ type: "web_search_20250305", name: "web_search", max_uses: maxSearches }],
        messages: [
          { role: 'user', content: prompt },
          // No assistant prefill — model must decide whether to search first
        ],
      }),
    });
    if (response.status !== 529 && response.status !== 429) break;
    const wait = response.status === 529 ? [2000, 5000, 10000][attempt] : 15000;
    console.warn(`[claude-stream-search] HTTP ${response.status}, retry ${attempt+1}/3 in ${wait/1000}s`);
    await sleep(wait);
  }
  if (!response || !response.body) return null;
  const reader = response.body.getReader();
  const decoder = new TextDecoder();
  let buffer = '';
  let fullText = '';           // All text from text-type content blocks
  let currentBlockType = null; // Track what kind of block we're in
  let searchFired = false;     // Did the model use web_search?
  while (true) {
    const { done, value } = await reader.read();
    if (done) break;
    buffer += decoder.decode(value, { stream: true });
    const lines = buffer.split('\n');
    buffer = lines.pop();
    for (const line of lines) {
      if (!line.startsWith('data: ')) continue;
      const data = line.slice(6).trim();
      if (data === '[DONE]') continue;
      try {
        const event = JSON.parse(data);
        // Track block starts to know when we're in text vs tool_use vs tool_result
        if (event.type === 'content_block_start') {
          currentBlockType = event.content_block?.type || null;
          if (currentBlockType === 'web_search_tool_result' || currentBlockType === 'tool_use') {
            if (!searchFired && onStatus) { onStatus("Searching..."); searchFired = true; }
          }
        }
        if (event.type === 'content_block_stop') {
          currentBlockType = null;
        }
        // Only accumulate text deltas from text blocks (not tool_use/tool_result)
        if (event.type === 'content_block_delta' && event.delta?.text && currentBlockType === 'text') {
          fullText += event.delta.text;
          if (onChunk) onChunk(fullText.replace(/<\/?cite[^>]*>/g, ""));
        }
      } catch { /* non-critical */ }
    }
  }
  // Parse: use extractJsonWithKey if anchor provided, else try direct parse
  try {
    const cleaned = fullText.replace(/<\/?cite[^>]*>/g, "").trim();
    if (anchorKey) {
      const result = extractJsonWithKey(cleaned, anchorKey);
      if (result) return stripCitations(result);
    }
    // Fallback: try to find JSON object in the text
    const firstBrace = cleaned.indexOf('{');
    const lastBrace = cleaned.lastIndexOf('}');
    if (firstBrace >= 0 && lastBrace > firstBrace) {
      return stripCitations(JSON.parse(cleaned.slice(firstBrace, lastBrace + 1)));
    }
    return null;
  } catch { return null; }
}

// callAI: JSON-specific wrapper around claudeFetch. Delegates all HTTP/retry
// logic to claudeFetch, then extracts + repairs JSON from the response.
async function callAI(prompt, { maxTokens = 5500 } = {}){
  const d = await claudeFetch({
    model:activeModel(),
    max_tokens:maxTokens,
    temperature:0,
    system:ANTI_HALLUCINATION_SYSTEM,
    messages:[
      {role:"user",content:prompt + '\n\nRespond with ONLY raw JSON starting with {. No prose, no markdown, no explanation.'},
    ],
  });
  if(d?.error) return null;
  let raw=(d.content||[]).filter(b=>b.type==="text").map(b=>b.text).join("").replace(/<\/?cite[^>]*>/g,"").trim();
  if(!raw) return null;
  // Strip markdown fences, thinking tags, and prose before JSON
  raw = raw.replace(/```(?:json)?\s*/gi, "").replace(/```\s*/g, "").replace(/<\/?thinking>/g, "").trim();
  // Find the first { and last } to extract JSON
  const firstBrace = raw.indexOf("{");
  const lastBrace = raw.lastIndexOf("}");
  if (firstBrace < 0 || lastBrace <= firstBrace) return null;
  const text = raw.slice(firstBrace, lastBrace + 1);
  const candidate = text;
  // Try 1: direct parse
  try{return JSON.parse(candidate);}catch{ /* non-critical */ }
  // Try 2: unicode sanitize + trailing comma removal
  const sanitized = candidate
    .replace(/[\u2018\u2019]/g,"'").replace(/[\u201C\u201D]/g,'"')
    .replace(/[\u2013\u2014]/g,"-").replace(/[\u2026]/g,"...")
    .replace(/[\x00-\x08\x0B\x0C\x0E-\x1F]/g,"")
    .replace(/,\s*([}\]])/g,"$1");
  try{return JSON.parse(sanitized);}catch{ /* non-critical */ }
  // Try 3: character-by-character JSON repair
  try{return JSON.parse(repairJSON(sanitized));}catch(e){
    console.error("JSON repair failed:",e.message);
  }
  return null;
}

// JSON repair: escapes unescaped quotes and raw newlines inside strings
function repairJSON(s) {
  let out="", inStr=false, esc=false;
  for(let i=0;i<s.length;i++){
    const ch=s[i];
    if(esc){out+=ch;esc=false;continue;}
    if(ch==="\\"){out+=ch;esc=true;continue;}
    if(inStr){
      if(ch==="\n"){out+="\\n";continue;}
      if(ch==="\r"){out+="\\r";continue;}
      if(ch==="\t"){out+="\\t";continue;}
      if(ch==='"'){
        let j=i+1;
        while(j<s.length){
          if(s[j]==="\n"||s[j]==="\r"||s[j]===" "||s[j]==="\t"){j++;continue;}
          if(s[j]==="\\"){j+=2;continue;}
          break;
        }
        const nxt=j<s.length?s[j]:"";
        if(nxt===","||nxt==="}"||nxt==="]"||nxt===":"||nxt===""){inStr=false;out+=ch;}
        else{out+='\\"';}
        continue;
      }
      out+=ch;
    }else{
      if(ch==='"'){inStr=true;out+=ch;continue;}
      out+=ch;
    }
  }
  return out;
}

// ── SANITIZE WEB SEARCH RESULTS ──────────────────────────────────────────
// Web search returns content from arbitrary websites. A malicious site
// could embed prompt injection patterns in its text. This recursively
// sanitizes all string values in an object returned from web search.
function sanitizeWebResult(obj) {
  if (!obj || typeof obj !== "object") return obj;
  if (Array.isArray(obj)) return obj.map(sanitizeWebResult);
  const clean = {};
  for (const [k, v] of Object.entries(obj)) {
    if (typeof v === "string") clean[k] = sanitizeForPrompt(v);
    else if (typeof v === "object" && v !== null) clean[k] = sanitizeWebResult(v);
    else clean[k] = v;
  }
  return clean;
}

// ── GENERATE BRIEF ────────────────────────────────────────────────────────────
// Build the unified "Seller Proof Pack" that gets prepended to every
// customer-facing prompt (brief, hypothesis, solution fit, fit-score).
// This is the system's "why buy from US" thread — without it, downstream
// prompts invent generic claims instead of citing real proof. The pack
// ── PROMPT INJECTION SANITIZER ────────────────────────────────────────────
// Strips common prompt injection patterns from user input before
// interpolation into AI prompts. Not a complete defense (impossible with
// LLMs), but raises the bar significantly against casual/automated attacks.
function sanitizeForPrompt(str) {
  if (typeof str !== "string") return str;
  // Normalize unicode to catch homoglyph bypasses (Greek Iota for Latin I, etc.)
  return str.normalize("NFKC")
    // Instruction override attempts
    .replace(/\b(ignore|disregard|forget|override|bypass|skip)\s+(all\s+)?(previous|above|prior|earlier|system|safety|your)\s+(instructions?|rules?|constraints?|prompts?|guidelines?|restrictions?)/gi, "[filtered]")
    // Persona switching
    .replace(/\b(you are now|act as|pretend to be|switch to|behave as|simulate|imagine you're|imagine you are|suppose you're|suppose you are|new instructions?:|from now on|entering.*mode|simulation mode|developer mode|DAN mode|jailbreak)/gi, "[filtered]")
    // System prompt references
    .replace(/\b(system\s*prompt|<\/?system>|<\/?instructions?>|<\/?prompt>|<\/?rules>)/gi, "[filtered]")
    // Extraction verbs + targets
    .replace(/\b(repeat|reveal|show|display|print|output|list|enumerate|recite|explain|describe|share|tell me|walk me through)\s+(your|the|all|me)?\s*(system\s*prompt|instructions?|rules?|knowledge\s*layer|internal|heuristics?|framework|scoring|methodology|algorithm|formula|process|approach|logic|dimensions?)/gi, "[filtered]")
    // Encoding/obfuscation
    .replace(/\b(translate|encode|base64|rot13|hex|binary|ascii|unicode|cipher|obfuscate|spell out|character by character|convert\s*to)\s+(your|the|these)?\s*(instructions?|rules?|prompt|system)/gi, "[filtered]")
    // Meta-questions about restrictions
    .replace(/\b(what are you not allowed|what can't you|what are your restrictions|what are your rules|what were you told|what instructions do you follow|what is your methodology|how do you score|how does scoring work|how do you rank|what makes a strong fit)/gi, "[filtered]")
    // Hypothetical/roleplay framing
    .replace(/\b(if you were|if you could|hypothetically|in a scenario where|let's say you)\s+(allowed|able|free|permitted|unrestricted)/gi, "[filtered]")
    // Script injection
    .replace(/<script[^>]*>[\s\S]*?<\/script>/gi, "")
    .replace(/[<>]/g, "")
    // Line-break injection — collapse runs of newlines that create fake section headers
    .replace(/\n{3,}/g, "\n\n")
    // Markdown/formatting injection — strip header markers and horizontal rules
    .replace(/^#{1,6}\s/gm, "")
    .replace(/^[═━─]{3,}/gm, "---")
    .replace(/^```[\s\S]*?```$/gm, "[code block filtered]");
}

// composes everything the seller has captured: ICP differentiators,
// named customers, competitive alternatives, success factors, priority
// trigger, traction channels, uploaded docs, and product catalog.
//
// CRITICAL: includes explicit instructions telling Haiku to GROUND every
// claim in this proof — cite named customers, name differentiators, flag
// unsupported claims rather than asserting them.
function buildSellerProofPack({ sellerICP, sellerDocs = [], products = [], sellerProofPoints = [], icpEdits = [], userEdits = [] }) {
  if (!sellerICP?.icp) return "";
  const icp = sellerICP.icp;
  const out = [];
  const sellerLabel = sellerICP.sellerName || sellerICP.marketCategory || "this seller";
  const s = sanitizeForPrompt;
  out.push(`═══ WHY BUY FROM ${s(sellerLabel).toUpperCase()} — ground every claim in this proof ═══`);
  if (sellerICP.sellerDescription) out.push(`What we sell: ${s(sellerICP.sellerDescription)}`);
  if (sellerICP.marketCategory)    out.push(`Market category: ${s(sellerICP.marketCategory)}`);

  const diffs   = (icp.uniqueDifferentiators || []).filter(Boolean);
  const cust    = (icp.customerExamples || []).filter(Boolean);
  const alts    = (icp.competitiveAlternatives || []).filter(Boolean);
  const channels= (icp.tractionChannels || []).filter(Boolean);

  if (diffs.length) {
    out.push(`\nUnique differentiators (name these to justify "why us"):`);
    diffs.forEach(d => out.push(`  • ${s(d)}`));
  }
  if (cust.length) {
    out.push(`\nNamed customers (cite by name as social proof when proposing solutions; do NOT invent other customer names):`);
    cust.forEach(c => out.push(`  • ${s(c)}`));
  }
  if (alts.length) {
    out.push(`\nCompetitive alternatives we displace/replace (know the terrain):`);
    alts.forEach(a => out.push(`  • ${s(a)}`));
  }
  if (icp.successFactors) {
    out.push(`\nWhat winning looks like for our customers (frame outcomes in these terms):`);
    out.push(`  ${s(icp.successFactors)}`);
  }
  if (icp.priorityInitiative) {
    out.push(`\nWhat triggers our buyers to act NOW (use this for urgency framing):`);
    out.push(`  ${s(icp.priorityInitiative)}`);
  }
  if (channels.length) {
    out.push(`\nProven go-to-market channels:`);
    channels.forEach(c => out.push(`  • ${s(c)}`));
  }
  if (sellerDocs.length) {
    out.push(`\nUploaded proof documents (case studies, datasheets — quote when relevant):`);
    sellerDocs.forEach(d => out.push(`  • ${s(d.label)}: ${s((d.content || "").slice(0, 800))}${d.content && d.content.length > 800 ? "…" : ""}`));
  }
  const namedProducts = (products || []).filter(p => p?.name?.trim());
  if (namedProducts.length) {
    out.push(`\nSeller's product catalog (use these EXACT names — do NOT invent products):`);
    namedProducts.forEach(p => out.push(`  • ${s(p.name)}${p.description ? " — " + s(p.description.slice(0, 300)) : ""}`));
  }

  // Manually-entered proof points (case studies, ROI metrics, awards, etc.)
  const validProofs = (sellerProofPoints || []).filter(p => p?.content?.trim());
  if (validProofs.length) {
    out.push(`\nVerified proof points (entered by the seller — cite these VERBATIM when relevant):`);
    validProofs.forEach(p => out.push(`  • [${p.type}] ${p.content}`));
  }

  // Seller exclusions — things the seller does NOT do (prevents capability mismatches)
  const exclusions = (sellerICP?.icp?.sellerExclusions || []).filter(Boolean);
  if (exclusions.length) {
    out.push(`\n═══ SELLER DOES NOT DO — HARD EXCLUSIONS ═══`);
    out.push(`The following capabilities, products, or services are OUTSIDE the seller's scope.`);
    out.push(`Do NOT suggest, recommend, or imply the seller can do any of these:`);
    exclusions.forEach(ex => out.push(`  ✗ ${s(ex)}`));
    out.push(`If a use case requires any excluded capability, OMIT that use case entirely from the brief. Do not suggest workarounds or adjacent positioning for excluded capabilities.`);
  }

  out.push(`\n═══ HOW TO USE THIS PROOF ═══`);
  out.push(`When you propose a solution, recommendation, talk track, or claim:`);
  out.push(`1. Cite a SPECIFIC named customer from the list above whenever you claim "we've done this before." Never invent customer names.`);
  out.push(`2. Use the unique differentiators above to justify "why us" — never assert generic capabilities.`);
  out.push(`3. Frame outcomes using the success factors above — concrete, measurable, the customer's language.`);
  out.push(`4. Quote from uploaded docs verbatim when they contain a relevant proof point or quantified outcome.`);
  out.push(`5. Use ONLY products from the catalog above — do NOT invent product names.`);
  out.push(`6. If you cannot ground a claim in the proof above, OMIT the claim entirely. Do NOT surface uncertainty inline — a brief should only contain claims the rep can confidently state. Unverified claims belong in a separate internal checklist, not the deliverable.`);
  out.push(`7. The customer should feel deeply understood, that the seller knows the BEST solution, and that this is a deal where everyone wins with measurable outcomes.`);
  out.push(`8. NEVER INVENT STATISTICS ABOUT THE SELLER. Do not fabricate customer counts, revenue numbers, market share, network size, retailer counts, or any other quantitative claim about the selling organization. Only cite numbers that appear in the proof points, uploaded docs, or ICP above. If you don't have a verified number, describe the capability qualitatively ("extensive retail network" not "500K+ retailers"). Making up stats destroys rep credibility.`);
  out.push(`9. NEVER INVENT FACTS ABOUT THE TARGET COMPANY. Do not fabricate revenue, employee counts, executives, products, partnerships, or acquisitions. Use training knowledge confidently for well-known companies. For genuinely unknown facts, use an empty string — do NOT write "[Verify]" or placeholder text. A rep who cites a wrong fact in a sales call loses credibility instantly.`);
  out.push(`10. NEVER attribute direct quotes to named executives unless you found the quote in web search results with a verifiable source. If no source URL exists, paraphrase instead ("Deloitte leadership has emphasized resilience" not "CEO said '...'"). Fabricated quotes are the single highest-risk hallucination category.`);

  // Append user corrections — these override any conflicting AI inference
  const editCtx = buildUserEditContext(icpEdits, userEdits);
  if (editCtx) out.push(editCtx);

  return out.join("\n") + "\n\n";
}

// ── USER EDIT CONTEXT ────────────────────────────────────────────────────
// Formats user ICP edits into a prompt injection that tells the AI engine
// to treat user corrections as highest-priority ground truth. User edits
// represent proprietary knowledge that may not be publicly available.
function buildUserEditContext(edits, userEdits) {
  const hasIcpEdits = edits?.length > 0;
  const hasUserEdits = userEdits?.length > 0;
  if (!hasIcpEdits && !hasUserEdits) return "";
  const out = ["\n═══ USER CORRECTIONS (HIGHEST PRIORITY — override all other signals) ═══"];
  out.push("The seller has manually edited data in this session. These corrections");
  out.push("reflect proprietary knowledge and MUST take precedence over web research,");
  out.push("training data, or any other inference. Treat these as ground truth.\n");
  // ICP edits — dedupe to most recent per field
  if (hasIcpEdits) {
    out.push("ICP EDITS:");
    const latest = {};
    edits.forEach(e => { latest[e.field] = e; });
    Object.values(latest).forEach(e => {
      out.push(`  CORRECTED: ${e.field}`);
      if (e.oldValue) out.push(`    Was: ${String(e.oldValue).slice(0, 200)}`);
      out.push(`    Now: ${String(e.newValue).slice(0, 200)}`);
    });
  }
  // General user edits (brief, intel, hypothesis) — dedupe per source+field+company
  if (hasUserEdits) {
    const bySource = {};
    userEdits.forEach(e => {
      const key = `${e.source}:${e.field}:${e.company}`;
      bySource[key] = e; // keep latest
    });
    const grouped = {};
    Object.values(bySource).forEach(e => {
      if (!grouped[e.source]) grouped[e.source] = [];
      grouped[e.source].push(e);
    });
    Object.entries(grouped).forEach(([source, items]) => {
      const label = source === "brief" ? "BRIEF EDITS" : source === "intel" ? "INTEL ADJUSTMENTS" : source.toUpperCase() + " EDITS";
      out.push(`\n${label}:`);
      items.slice(-10).forEach(e => {
        out.push(`  ${e.company ? e.company + " · " : ""}${e.field}: ${e.newValue}`);
      });
    });
  }
  out.push("\nWhen any AI-generated content conflicts with these corrections, ALWAYS");
  out.push("use the corrected values. The user knows their business better than any model.\n");
  return out.join("\n");
}

// generateBrief is NON-ASYNC so it returns skeleton + raw promises
// immediately. pickAccount (the only caller) then renders the skeleton
// right away and merges each micro-result as it resolves — no blocking
// wait for p1. This cuts time-to-first-paint from ~3-5s to instant.
function generateBrief(member, sellerUrl, sellerDocs, products, selectedCohort, selectedOutcomes, productPageUrl, onStatus, productUrls=[], sellerICP=null, caches={}, onStream=null, icpEdits=[], accountDocs=[]){
  const co  = sanitizeForPrompt(member.company);
  const url = member.company_url || co;
  const safeSellerUrl = sanitizeForPrompt(sellerUrl);
  // Set tracking context for all API calls during this brief generation
  setTrackingContext(member.company, sellerUrl, sellerUrl === "research-only" ? "quick-brief" : "full-brief");

  const activeProductUrls = productUrls.filter(u=>u.url.trim()).map(u=>sanitizeForPrompt(u.url.trim()));
  const sellerCtx = sellerDocs.length>0
    ? "SELLER DOCS:\n"+sellerDocs.map(d=>sanitizeForPrompt(d.label)+": "+sanitizeForPrompt(d.content.slice(0,400))).join("\n")
    : "Seller: "+safeSellerUrl+(activeProductUrls.length?" | Pages: "+activeProductUrls.join(", "):"");
  const prodCtx = products.filter(p=>p.name.trim()).length>0
    ? "\nPRODUCTS: "+products.filter(p=>p.name.trim()).map(p=>p.name+(p.description?" - "+p.description.slice(0,60):"")).join("; ")
    : "";
  // Every company always wants these — inject as baseline context even if not explicitly selected
  const activeOutcomes = selectedOutcomes?.length>0
    ? selectedOutcomes
    : ["Revenue growth","Customer satisfaction","Compliance","Fraud reduction","Investor returns","Market expansion"];
  const dealCtx = `${selectedCohort?.name||""} | Industry: ${member.ind||""} | Outcomes: ${activeOutcomes.join(", ")}`;
  const universalCtx = `ASSUME: Every company universally wants to grow revenue, expand markets, stay compliant, reduce fraud/risk, satisfy investors, and make customers happy. Frame all briefs through these lenses even when not explicitly stated.\n`+`GARTNER BUYING REALITY: Buyers spend only 17% of their time with vendors. The seller must use that time to demonstrate they already understand the buyer's industry, challenge a widely-held assumption, and make the next step obvious and small. Score accounts on how much they NEED this insight, not just whether they could use the product.`;

  // Proof pack for p3/p4 — includes differentiators, named customers, product
  // catalog, and proof points. generateBrief doesn't have sellerProofPoints
  // in scope (it's component state, not a param) — those are injected by the
  // component-level calls (hypothesis, post-call, solution fit).
  const proofPack = buildSellerProofPack({ sellerICP, sellerDocs, products, icpEdits });

  // TWO context levels. baseLight is for target-research-only calls (p1, p5)
  // that don't need the seller proof pack, scoring heuristics, or deal context.
  // baseFull is for seller-mapping calls (p3, p4) that need everything.
  // This cuts ~1,500 input tokens off p1 and p5, making them resolve ~40% faster.
  // APOLLO ENRICHMENT GROUNDING: when enrichment data is available, inject
  // verified firmographics so the model doesn't guess basic facts.
  const enrichment = member._enrichment?.organization;
  const enrichedPeople = member._enrichment?.people || [];
  const enrichmentCtx = enrichment ? `\nVERIFIED COMPANY DATA (from Apollo.io — use these facts as ground truth, do NOT contradict them):\n` +
    (enrichment.name ? `Company name: ${enrichment.name}\n` : "") +
    (enrichment.description ? `Description: ${enrichment.description}\n` : "") +
    (enrichment.employeeCount ? `Employees: ${enrichment.employeeCount}\n` : "") +
    (enrichment.revenue ? `Revenue: ${enrichment.revenue}\n` : "") +
    (enrichment.industry ? `Industry: ${enrichment.industry}${enrichment.subIndustry ? ` / ${enrichment.subIndustry}` : ""}\n` : "") +
    (enrichment.headquarters ? `HQ: ${enrichment.headquarters}\n` : "") +
    (enrichment.founded ? `Founded: ${enrichment.founded}\n` : "") +
    (enrichment.publiclyTraded ? `Publicly traded: ${enrichment.publiclyTraded}\n` : "") +
    (enrichment.fundingTotal ? `Total funding: ${enrichment.fundingTotal}\n` : "") +
    (enrichment.latestFundingRound ? `Latest funding: ${enrichment.latestFundingRound}${enrichment.latestFundingAmount ? ` ($${enrichment.latestFundingAmount})` : ""}${enrichment.latestFundingDate ? ` (${enrichment.latestFundingDate})` : ""}\n` : "") +
    (enrichment.technologies?.length ? `Tech stack: ${enrichment.technologies.slice(0, 15).join(", ")}\n` : "") +
    (enrichment.linkedIn ? `LinkedIn: ${enrichment.linkedIn}\n` : "") +
    (enrichedPeople.length ? `\nKEY PEOPLE (verified from Apollo — use these names and titles as ground truth):\n` +
      enrichedPeople.slice(0, 8).map(p => `- ${p.name}, ${p.title}${p.department ? ` (${p.department})` : ""}${p.linkedIn ? ` — ${p.linkedIn}` : ""}`).join("\n") + "\n" : "") +
    "\n" : "";

  // PUBLIC COMPANY: inject SEC filing search instructions for publicly traded targets
  const isPublicCompany = !!(
    (enrichment?.publiclyTraded && !/private/i.test(enrichment.publiclyTraded)) ||
    (member.publicPrivate && /public/i.test(member.publicPrivate))
  );
  const secFilingCtx = isPublicCompany ? `\nSEC FILING INTELLIGENCE (PUBLICLY TRADED company — use these authoritative sources):\nSearch queries to include:\n- site:sec.gov "${co}" 10-K (annual report — strategy, capex, risk factors)\n- "${co}" earnings call transcript 2025 (CEO/CFO strategic statements)\n- "${co}" proxy statement DEF 14A (board composition, governance)\nWhat to extract:\n- 10-K Item 7 (MD&A): Forward-looking strategy, capital plans, modernization initiatives, procurement intent\n- 10-K Item 1A (Risk Factors): Competitive gaps, technology needs, regulatory pressures\n- 10-K Item 1 (Business): Segments, revenue breakdown, key customers, market position\n- Proxy (DEF 14A): Board members, committees, activist investors, mandates\n- Earnings calls: CEO/CFO direct quotes on priorities, guidance, investments\nCite specific filing dates and data (e.g. "Per 10-K filed 2/28/2025, revenue grew 12% YoY to $4.2B"). SEC filings are the highest-quality source for public companies.\n` : "";

  // IDENTITY ANCHOR: when a URL is available, use it as the primary identifier
  // to prevent cross-company contamination in briefs.
  const identityAnchor = url && url !== co
    ? `IDENTITY ANCHOR: Research ONLY the company at https://${url}. The company name "${co}" may be shared by multiple entities — use the website ${url} as the definitive identifier. Every fact in this brief must be about the company that operates ${url}. If you find conflicting information about different companies with similar names, ONLY use information about the entity at ${url}.\n\n`
    : `IDENTITY: Research the company "${co}". If multiple companies share this name, focus on the most prominent/well-known entity. Do NOT mix facts from different companies.\n\n`;

  // Canonical seller name — use consistently across all sections
  const canonicalSellerName = sellerICP?.sellerName || sellerUrl || "the seller";
  const baseLight =
    `Sales brief about TARGET PROSPECT "${co}"${url && url !== co ? ` (${url})` : ""} for seller "${canonicalSellerName}"${sellerUrl !== canonicalSellerName ? ` (${sellerUrl})` : ""}.\n`+
    `SELLER NAME CONSISTENCY: Always refer to the selling organization as "${canonicalSellerName}" — not "${sellerUrl}" or any other variation. Use this exact name in every section.\n`+
    identityAnchor +
    enrichmentCtx +
    secFilingCtx +
    `RULE: All fields describe ${co} NOT the seller. ASCII only.\n`+
    `EMPTY FIELD RULE (CRITICAL): If a fact is unknown, return an EMPTY STRING "". NEVER return "Not found", "Not specified", "Not available", "N/A", "Unknown", "[Verify]", or any placeholder text. The UI handles empty fields gracefully — placeholder text breaks the display. Empty string is ALWAYS correct for unknown data.\n`+
    `ACCURACY: NEVER invent facts about ${co} — no fabricated revenue, employee counts, executives, products, partnerships, or acquisitions. If unknown, use an empty string.\n`+
    `DATA CONFIDENCE RULE (CRITICAL — a brief with 5 verified facts is worth more than one with 15 guesses):\n`+
    `- If web search found no data for a field, return empty string "" — do NOT fill it from training knowledge alone.\n`+
    `- If a figure is uncertain, present as a range (e.g. "$2-3B") or add "(estimate)" — never state an uncertain figure as fact.\n`+
    `- For data-scarce targets (mutuals, private companies, small firms, nonprofits): include "Limited public data available" in companySnapshot so the rep knows to verify before the call.\n`+
    `- NEVER fabricate a Glassdoor rating, revenue figure, executive name, or acquisition that did not appear in web search results or the Apollo data above.\n`+
    `- A rep who cites a wrong fact in a sales call loses credibility permanently. Empty is safe; wrong is fatal.\n`+
    `CONSISTENCY: Return EXACTLY the structure shown — same field names, same array lengths.\n`+
    `STABILITY: For the same company, your output should be stable across runs. Use established facts (revenue, HQ, founding year, executive names) not ephemeral observations. Anchor every claim in verifiable data, not interpretive commentary that could vary between runs. If multiple descriptions are equally valid, prefer the most specific and factual one.\n\n`+
    // Account-specific intel docs (RFPs, requirements, discovery Qs, meeting notes)
    (accountDocs.length > 0
      ? `TARGET-SPECIFIC INTEL (uploaded by the user — these are documents FROM or ABOUT ${co}. Treat as high-priority context. Address their specific requirements, questions, and priorities throughout the brief):\n` +
        accountDocs.map(d => sanitizeForPrompt(d.label) + ": " + sanitizeForPrompt(d.content.slice(0, 800))).join("\n") + "\n\n"
      : "");

  const verticalCtx = getVerticalInjection(sellerICP, member.ind);
  const paymentsCtx = getPaymentsInjection(sellerICP, member.ind);

  // ── Track which knowledge layers were injected for this brief ──────────
  // Each entry: [humanName, injectionResult]. After computing all injections,
  // collect names of non-empty ones into _klVersions on the brief skeleton.
  const _klInjections = [
    ["vertical", verticalCtx],
    ["payments", paymentsCtx],
    ["compliance", getComplianceInjection(sellerICP, member.ind)],
    ["realEstate", getRealEstateInjection(sellerICP, member.ind)],
    ["banking", getBankingInjection(sellerICP, member.ind)],
    ["healthcare", getHealthcareInjection(sellerICP, member.ind)],
    ["aiMl", getAiMlInjection(sellerICP, member.ind)],
    ["fintechDeep", getFintechDeepInjection(sellerICP, member.ind)],
    ["rewards", getRewardsInjection(sellerICP, member.ind)],
    ["qsr", getQsrInjection(sellerICP, member.ind)],
    ["investor", getInvestorInjection(sellerICP, member.ind)],
    ["baas", getBaasInjection(sellerICP, member.ind)],
    ["charitable", getCharitableInjection(sellerICP, member.ind)],
    ["medicalPayments", getMedicalPaymentsInjection(sellerICP, member.ind)],
    ["smbMidmarket", getSmbMidmarketInjection(sellerICP, member.ind, member)],
    ["insurance", getInsuranceInjection(sellerICP, member.ind)],
    ["digitalIncentives", getDigIncentivesInjection(sellerICP, member.ind)],
    ["retail", getRetailInjection(sellerICP, member.ind)],
    ["professionalServices", getProfServicesInjection(sellerICP, member.ind)],
    ["manufacturing", getManufacturingInjection(sellerICP, member.ind)],
    ["cannabis", getCannabisInjection(sellerICP, member.ind)],
    ["crypto", getCryptoInjection(sellerICP, member.ind)],
    ["gaming", getGamingInjection(sellerICP, member.ind)],
    ["predictionMarkets", getPredictionMarketsInjection(sellerICP, member.ind)],
    ["cybersecurity", getCybersecurityInjection(sellerICP, member.ind)],
    ["education", getEducationInjection(sellerICP, member.ind)],
    ["energy", getEnergyInjection(sellerICP, member.ind)],
    ["hrTech", getHrTechInjection(sellerICP, member.ind)],
    ["government", getGovernmentInjection(sellerICP, member.ind)],
    ["executivePerspectives", KL_EXEC_PERSPECTIVES ? "\n" + KL_EXEC_PERSPECTIVES : ""],
    ["approvalGates", KL_APPROVAL_GATES ? "\n" + KL_APPROVAL_GATES : ""],
    ["peHoldco", KL_PE_HOLDCO ? "\n" + KL_PE_HOLDCO : ""],
    // Cross-cutting layers (always injected when present, not keyword-gated)
    ["accounting", KL_ACCOUNTING ? "\n" + KL_ACCOUNTING : ""],
    ["b2bSales", KL_B2B_SALES ? "\n" + KL_B2B_SALES : ""],
    ["okrKpi", KL_OKR_KPI ? "\n" + KL_OKR_KPI : ""],
  ];
  const _klActiveVersions = _klInjections.filter(([, v]) => v).map(([name]) => name);
  const _klInjectionText = _klInjections.map(([, v]) => v).join("");

  const baseFull = baseLight +
    `${universalCtx}\n`+
    `SELLER CONTEXT:\n${sellerCtx}${prodCtx}\n`+
    proofPack +
    _klInjectionText +
    `DEAL: ${dealCtx}\n\n`;

  onStatus("Researching "+co+"...");

  // ── 5 MICRO-CALLS fire simultaneously, each with a tiny schema ───────────
  // User sees the overview card the moment the fastest resolves (~2s)

  // MICRO 1: Company overview. Pre-cache (web_search, rich) → instant hit.
  // Inline fallback NOW ALSO uses web_search via streamAIWithSearch so that
  // cache misses still get grounded data instead of training-data-only.
  // The pre-cache fires on account select (step 4) with web_search — by the
  // time the user clicks Build Brief, it's usually ready.
  const preCache = caches.brief || {};
  const overviewCache = preCache.overview;
  const p1 = overviewCache
    ? (overviewCache instanceof Promise ? overviewCache : Promise.resolve(overviewCache))
    : streamAIWithSearch(baseLight+
    `OWNERSHIP ACCURACY — CRITICAL:\n`+
    `- Many companies have CHANGED ownership status. Do NOT rely on stale data. Common examples: Blackhawk Network went private (acquired 2018), Dell went private then re-IPO'd, Worldpay was acquired by FIS then spun out to Global Payments.\n`+
    `- If a company was acquired, taken private, or delisted, it is PRIVATE — do NOT show a ticker.\n`+
    `- The publicPrivate field and fundingProfile field MUST agree. If fundingProfile says "PE-backed" or "Acquired by X", then publicPrivate MUST say "Private" — never "Public" with a ticker.\n`+
    `- Only include a stock ticker if you are 100% certain the company is CURRENTLY publicly traded on that exchange. When in doubt, write "Private" or "Public" without a ticker.\n\n`+
    `Return ONLY raw JSON (start with {) for the company overview:\n`+
    `{"companySnapshot":"3-4 sentences: what ${co} does, market position, recent moves. Be specific.",`+
    `"revenue":"e.g. $2.4B (FY2024) — use ONLY figures from web search or Apollo data. Empty string if not found.","publicPrivate":"MUST be accurate as of today — 'Public (NASDAQ: TICKER)' ONLY if currently listed, otherwise 'Private' or 'Private (PE-backed)' or 'Private (acquired by X)'","employeeCount":"e.g. ~200,000",`+
    `"headquarters":"City, State","founded":"Year","website":"domain.com","linkedIn":"ONLY the exact LinkedIn company page URL if you are certain it's correct (e.g. linkedin.com/company/gusto). A wrong LinkedIn link is worse than no link. Empty string if unsure.",`+
    `"fundingProfile":"Ownership structure — MUST match publicPrivate field. PE firm + year, or Series + total raised, or Public exchange+ticker. If acquired, name the acquirer and year.",`+
    `"competitors":["ONLY direct competitors in the same product category — from web search results. Empty array if none found. Do NOT list companies from adjacent categories."],`+
    `"watchOuts":["PROCUREMENT: Flag structurally-difficult targets and recommend channel/partner path.","INCUMBENT: Name the specific vendor relationship to displace or land adjacent to.","CREDIBILITY: Assess seller-stage fit."]}`,
    (partial) => {
      if (!onStream || partial.length < 40) return;
      const snapMatch = partial.match(/"companySnapshot"\s*:\s*"((?:[^"\\]|\\.)*)"/);
      if (snapMatch) onStream("overview", { companySnapshot: snapMatch[1].replace(/\\"/g, '"').replace(/\\n/g, '\n') });
    }, 1800, { maxSearches: 1, anchorKey: "companySnapshot", onStatus, model: SONNET }
  );

  // MICRO 2: Executives — reuse pre-cache promise/result. Never duplicate.
  const execCache = caches.execs;
  const p2 = execCache
    ? (execCache instanceof Promise ? execCache : Promise.resolve(execCache))
    : (async()=>{
    // No pre-cache — fire inline. Mark as billable run (1 per brief).
    const execPrompt = baseLight+
      (sellerICP?.sellerDescription ? `Seller context: ${sellerICP.sellerDescription} (${sellerICP?.marketCategory||""}). Products: ${products.filter(p=>p.name?.trim()).map(p=>p.name).join(", ")||"various"}.\n\n` : "")+
      `Search for the CURRENT leadership team of ${co}. Return 4-6 people.\n\n`+
      `SEARCH STRATEGY — use BOTH searches:\n`+
      `1. Search "${co} leadership team" OR "${co} founders" OR "${co} about us team"\n`+
      `2. Search "site:linkedin.com ${co}" to find executives on LinkedIn\n`+
      `For smaller companies, startups, and nonprofits: the "About", "Our Team", or "Leadership" page on their website is the BEST source. Founders and co-founders count as executives.\n\n`+
      `ACCURACY RULES (CRITICAL — executive errors destroy deals):\n`+
      `- EXECUTIVES CHANGE JOBS. Your training data may be stale. A name you "know" may have LEFT the company months or years ago. ALWAYS verify via web search that the person is CURRENTLY at ${co} before including them.\n`+
      `- If your search shows an executive has LEFT ${co} (moved to a competitor, retired, was replaced), do NOT include them. Including a departed executive is worse than omitting them — a rep who names someone who left looks uninformed.\n`+
      `- 3 verified CURRENT executives is better than 6 that include departed ones. Accuracy over completeness.\n`+
      `- For smaller companies / startups / nonprofits: the founding team IS the leadership team. Return founders, co-founders, board members, and any named team leads.\n`+
      `- NEVER return "Verify at LinkedIn" or any placeholder — either return the real name or omit entirely.\n`+
      `- Include: CEO/Founder, COO/Co-Founder, CTO, CFO, and any named leaders. For small orgs, board members and advisors count.\n`+
      `- When in doubt about whether someone is still at ${co}, OMIT them. A shorter list of verified current executives is always better than a longer list with stale names.\n\n`+
      `For each executive provide:\n`+
      `- name: their full real name (NEVER a placeholder)\n`+
      `- title: their exact current title\n`+
      `- initials: first letter of first + last name\n`+
      `- background: 1 sentence — prior company, prior role, board seats, or notable career move\n`+
      `- angle: Their MANDATE and PERSPECTIVE at ${co}. What were they hired to do? What strategic priority do they own? What keeps them up at night? How should a seller at ${sellerUrl} approach them? 2-3 specific sentences grounded in ${co}'s current situation and recent moves.\n`+
      (KL_EXEC_PERSPECTIVES ? `  USE THESE ROLE ARCHETYPES to write richer angles:\n  - CFO: margins, cash flow, audit, cost structure. Lead with ROI.\n  - CRO: pipeline, quota, win rate, expansion. Lead with revenue impact.\n  - CIO: architecture, integration, security, modernization. Lead with technical fit.\n  - CISO: breach risk, compliance, vendor risk. Lead with security posture.\n  - CHRO: talent, retention, culture, engagement. Lead with employee impact.\n  - COO: efficiency, process, scale, cost. Lead with operational improvement.\n  - CMO: brand, demand gen, martech, attribution. Lead with growth.\n  Match the angle to the SPECIFIC role — don't write generic angles.\n\n` : "\n")+
      `Return ONLY raw JSON:\n`+
      `{"keyExecutives":[{"name":"Full Name","title":"CEO","initials":"FN","background":"Prior role at Prior Company","angle":"Their mandate at ${co}. 2-3 sentences."}],`+
      `"sellerSnapshot":"2 sentences on ${sellerUrl} for ${co}"}`;

    const parseExecResponse = (d) => {
      if(d.error) return null;
      const textBlocks=(d.content||[]).filter(b=>b.type==="text").map(b=>b.text||"");
      for(let i=textBlocks.length-1;i>=0;i--){
        const parsed=extractJsonWithKey(textBlocks[i],"keyExecutives");
        if(parsed?.keyExecutives?.length) return parsed;
      }
      const raw=textBlocks.join("").trim();
      const fallback = safeParseJSON(raw.startsWith("{")?raw:"{"+raw);
      if(fallback?.keyExecutives?.length) return fallback;
      return null;
    };

    try {
      // Phase 1: web search for current executives (Sonnet — exec accuracy is critical)
      const d = await claudeFetch({
        model: SONNET,
        max_tokens:3000,
        tools:[{type:"web_search_20250305",name:"web_search",max_uses:2}],
        messages:[{role:"user",content:execPrompt}],
      }, { extraHeaders: { "x-billable-run": "1" } });
      const result = parseExecResponse(d);
      if(result?.keyExecutives?.length) return result;

      // Phase 2: fallback — no web search, use training knowledge only
      console.log(`[p2] Web search returned no executives for ${co}, falling back to training knowledge`);
      const d2 = await claudeFetch({
        model: SONNET,
        max_tokens:3000,
        messages:[{role:"user",content:
          `You are a senior sales researcher. Return the CURRENT leadership team of "${co}".\n\n`+
          `WARNING: This is a FALLBACK call without web search. Your training data may be STALE. Executives change jobs frequently. If you are not confident that a person is CURRENTLY at ${co} as of 2025-2026, do NOT include them. A rep who names a departed executive in a sales call loses credibility instantly.\n\n`+
          `Use your training knowledge but ONLY for executives you are highly confident are still at the company. Better to return 2 people you're sure about than 6 that include someone who left.\n`+
          `For SMALL COMPANIES, STARTUPS, and NONPROFITS: return founders, co-founders, board members, and any named team leads. 2 verified founders is a valid result.\n`+
          `For LARGE COMPANIES: return CEO, CFO, COO, CTO/CIO, and 1-2 functional leaders — ONLY if you're confident they're current.\n\n`+
          `For each: name (real full name), title, initials, background (1 sentence), angle (2-3 sentences on their mandate and how a seller at ${sellerUrl} should approach them).\n\n`+
          `If you genuinely don't know a specific name, use the ROLE as the name (e.g. "CEO" with title "Chief Executive Officer") and set background to "Verify current leadership via LinkedIn or company About page".\n\n`+
          `You MUST return at least 2 people. Prefer role-based stubs over potentially stale named executives.\n\n`+
          `Return ONLY raw JSON:\n`+
          `{"keyExecutives":[{"name":"Full Name","title":"CEO","initials":"FN","background":"Prior role","angle":"Their mandate. 2-3 sentences."}],`+
          `"sellerSnapshot":"2 sentences on ${sellerUrl} for ${co}"}`
        }],
      });
      const result2 = parseExecResponse(d2);
      if(result2?.keyExecutives?.length) return result2;

      // Phase 3: absolute last resort — return role-based stubs so the brief is never empty
      console.warn(`[p2] Both phases failed for ${co}, returning role stubs`);
      return {
        keyExecutives: [
          {name:"CEO",title:"Chief Executive Officer",initials:"CEO",background:"Research needed — verify via LinkedIn",angle:`As CEO of ${co}, this person sets strategic direction. Research their background and recent public statements to find the right angle.`},
          {name:"CFO",title:"Chief Financial Officer",initials:"CFO",background:"Research needed — verify via LinkedIn",angle:`The CFO controls budget allocation. Lead with ROI, cost reduction, or revenue impact to get their attention.`},
          {name:"CTO",title:"Chief Technology Officer",initials:"CTO",background:"Research needed — verify via LinkedIn",angle:`The CTO evaluates technical fit. Lead with architecture, integration, and security posture.`},
          {name:"COO",title:"Chief Operating Officer",initials:"COO",background:"Research needed — verify via LinkedIn",angle:`The COO owns operational efficiency. Lead with process improvement, time savings, and measurable operational outcomes.`},
        ],
        sellerSnapshot: `${sellerUrl} provides solutions relevant to ${co}'s market.`,
      };
    }catch(e){
      console.warn("Exec search failed:",e.message);
      return {
        keyExecutives: [
          {name:"CEO",title:"Chief Executive Officer",initials:"CEO",background:"Research needed — verify via LinkedIn",angle:`As CEO of ${co}, this person sets strategic direction. Research their background to find the right angle.`},
          {name:"CFO",title:"Chief Financial Officer",initials:"CFO",background:"Research needed — verify via LinkedIn",angle:`The CFO controls budget allocation. Lead with ROI and cost impact.`},
          {name:"CTO",title:"Chief Technology Officer",initials:"CTO",background:"Research needed — verify via LinkedIn",angle:`The CTO evaluates technical fit. Lead with architecture and integration.`},
          {name:"COO",title:"Chief Operating Officer",initials:"COO",background:"Research needed — verify via LinkedIn",angle:`The COO owns operational efficiency. Lead with process improvement and measurable outcomes.`},
        ],
        sellerSnapshot: `${sellerUrl} provides solutions relevant to ${co}'s market.`,
      };
    }
  })();

  // MICRO 3: Strategy + opening angle — needs seller context for "why you"
  // NOW WEB-GROUNDED: uses streamAIWithSearch so elevator pitch, strategic
  // theme, opening angle, and sentiment are grounded in live search results
  // rather than fabricated from training data.
  const p3 = streamAIWithSearch(baseFull+
    `SEARCH INSTRUCTION: Search for "${co}" recent strategy, news, earnings, and market position. Use the search results to ground every claim in your analysis.\n\n`+
    `TEACHING ANGLE: ${KL_CHALLENGER.teachingAngle || "Challenge a widely-held assumption about their industry"}. ${KL_CHALLENGER.mobilizer?.identify || "Look for the person who asks how to make it happen"}\n`+
    `SOCIAL PROOF: Name a SPECIFIC similar company as proof. Lead with a precise stat or insight.\n`+
    `DEPTH REQUIREMENT: Every field must contain SPECIFIC, actionable intelligence — not generic descriptions. "They're focused on digital transformation" is useless. "${co} is investing $200M in cloud migration after their Q3 earnings miss" is valuable.\n`+
    `STABILITY: Anchor your analysis in verifiable, durable facts — not interpretive commentary. Revenue, headcount, HQ, founding year, named initiatives, public statements, and executive names are stable. Avoid subjective framing that could change between runs.\n`+
    `GROUNDING RULES (learned from audit — CRITICAL):\n`+
    `- Do NOT invent executive names. If you're unsure who the CEO is, describe the role without naming anyone. "The CEO" not "CEO Jane Doe."\n`+
    `- Do NOT fabricate statistics about the seller (customer counts, revenue, market share). Only cite numbers from the proof pack above.\n`+
    `- Do NOT suggest use cases that require capabilities in the seller's exclusion list.\n`+
    `- Do NOT attribute direct quotes to executives unless you found the quote in web search results. Paraphrase instead.\n`+
    `- Every claim must be grounded in either (a) your web search results, or (b) the seller proof pack. If neither provides data for a field, return an empty string — do NOT guess from training knowledge. A brief with 5 verified facts is worth more than one with 15 guesses.\n\n`+
    `Return ONLY raw JSON (start with {) for strategy and seller angle:\n`+
    `{"elevatorPitch":"A 45-second spoken pitch (~90-100 words) that a seller would deliver when they bump into a ${co} executive in an elevator, at a conference, or on a cold call. Requirements: (1) Open with something SPECIFIC about ${co} that proves you did your homework — a recent move, initiative, or challenge FROM YOUR SEARCH RESULTS. (2) Bridge to WHY the seller's expertise matters for THAT specific situation. (3) End with a soft ask — a question or next step that's easy to say yes to. Tone: confident but not salesy, knowledgeable but not lecturing, human and conversational. Write it as actual spoken words — contractions, natural rhythm, no buzzwords. Should feel like the smartest person at the party, not a brochure.",`+
    `"strategicTheme":"3-4 sentences on ${co}'s CURRENT strategic direction. Cite specific initiatives, investments, or leadership statements FROM YOUR SEARCH RESULTS. What are they building toward in the next 12-18 months? What's driving urgency? Name a recent move (acquisition, hire, product launch, earnings statement) that reveals where they're headed. If search returned nothing, say so briefly rather than fabricating.",`+
    `"sellerOpportunity":"2-3 sentences: why ${sellerUrl} is well-positioned RIGHT NOW for ${co}. Connect a specific seller capability to a specific ${co} pain point or initiative. Name the gap the seller fills that no incumbent currently addresses.",`+
    `"openingAngle":"1-2 sharp sentences that would make a ${co} executive stop scrolling. Reference something REAL and RECENT about ${co} FROM YOUR SEARCH RESULTS — a hiring pattern, earnings call quote, competitive move, or industry shift. Reframe an assumption they hold. Sound human, not scripted. This should be the kind of thing that gets a reply.",`+
    `"publicSentiment":{`+
    `"onlineSentiment":"2-3 sentences synthesizing what employees, press, and the market say about ${co} as a COMPANY TO SELL INTO. Focus on: employee morale (Glassdoor themes), leadership reputation, workplace culture signals, press narrative, and brand health. This is NOT about their product quality vs competitors — it's about what a seller needs to know before calling.",`+
    `"glassdoorRating":"Glassdoor employer rating as a number e.g. '3.8'. Use ONLY a rating found in your web search results. If search did not return a Glassdoor rating, return empty string. Do NOT guess or estimate from training knowledge. NEVER 'Not found'.",`+
    `"g2Rating":"G2 rating as number e.g. 4.2 — only for software/SaaS companies, empty string otherwise. Use ONLY ratings from search results.",`+
    `"npsSignal":"Consumer brand health signals when relevant (brand loyalty, market share trajectory, customer satisfaction trends). Useful context for understanding the company's position, not for comparing their products to competitors. Empty string if not found in search.",`+
    `"trustpilotRating":"Trustpilot or BBB score if relevant — empty string if not found in search results",`+
    `"employeeScore":"Glassdoor CEO approval % or Indeed/Comparably employer rating — use ONLY data from search results. CRITICAL: do NOT invent or guess CEO/executive names in this field. If you are not certain of the current CEO's name, write the metric without naming anyone. A fabricated executive name destroys credibility instantly. Empty string if not found.",`+
    `"standoutReview":{"text":"Most revealing quote from an EMPLOYEE review (Glassdoor/Indeed) or a press piece about the company found in your search results — something that tells a seller what it's like to work with or sell into this organization. Empty string if search found nothing.","source":"Glassdoor / Indeed / press / analyst — name the actual source from search","sentiment":"positive or negative"},`+
    `"salesAngle":"1 sentence: how the seller should USE this sentiment context in the discovery conversation — a specific talk-track pivot, not just 'mention their pain'"}}`,
    (partial) => {
      if (!onStream || partial.length < 60) return;
      const pitchMatch = partial.match(/"elevatorPitch"\s*:\s*"((?:[^"\\]|\\.)*)"/);
      const themeMatch = partial.match(/"strategicTheme"\s*:\s*"((?:[^"\\]|\\.)*)"/);
      const angleMatch = partial.match(/"openingAngle"\s*:\s*"((?:[^"\\]|\\.)*)"/);
      const oppMatch = partial.match(/"sellerOpportunity"\s*:\s*"((?:[^"\\]|\\.)*)"/);
      if (pitchMatch || themeMatch || angleMatch || oppMatch) {
        const data = {};
        if (pitchMatch) data.elevatorPitch = pitchMatch[1].replace(/\\"/g, '"').replace(/\\n/g, '\n');
        if (themeMatch) data.strategicTheme = themeMatch[1].replace(/\\"/g, '"').replace(/\\n/g, '\n');
        if (angleMatch) data.openingAngle = angleMatch[1].replace(/\\"/g, '"').replace(/\\n/g, '\n');
        if (oppMatch) data.sellerOpportunity = oppMatch[1].replace(/\\"/g, '"').replace(/\\n/g, '\n');
        onStream("strategy", data);
      }
    }, 3800, { maxSearches: 1, anchorKey: "elevatorPitch", onStatus, model: OPUS }
  );
  // relationshipSignals feature tabled

  // MICRO 4: Solution mapping + contacts — shows after strategy
  // NOW WEB-GROUNDED: uses streamAIWithSearch so key contacts, tech stack,
  // and organizational intelligence are grounded in live search results.
  // GROUNDING REQUIREMENT: every solution must cite a specific differentiator
  // and (when possible) a named customer from the seller's proof pack above.
  const isResearchOnly = sellerUrl === "research-only";
  const p4 = streamAIWithSearch(baseFull+
    `SEARCH INSTRUCTION: Search for "${co}" leadership team, technology stack, and organizational structure. Use the search results to ground contacts and tech stack.\n\n`+
    `Return ONLY raw JSON (start with {) for ${isResearchOnly ? "organizational intelligence" : "solution fit and contacts"}:\n`+
    (isResearchOnly
      ? `This is a RESEARCH-ONLY brief. There is no selling organization. You MUST still populate ALL fields below:\n`+
        `- solutionMapping: leave as empty array []\n`+
        `- keyContacts: identify 2-3 key decision-makers at ${co} by likely title and function — VP level or above. Use ONLY names found in your web search results or the Apollo-verified contacts above. If search returned no names for a role, leave name as empty string but still fill in the title and angle.\n`+
        `- techStack: use your web search results to identify ${co}'s technology stack. If not found in search, return empty string for that field — do NOT guess.\n`+
        `- mobilizer: describe who at ${co} would champion a new technology purchase — what title, what motivates them, how to identify them.\n`+
        `- processMaturity: assess ${co}'s operational maturity (Define/Measure/Analyze/Improve/Control) based on their industry and size.\n`+
        `CRITICAL: Do NOT return empty objects. Every field except solutionMapping must have substantive content.\n`
      : `Map seller solutions to ${co} using positioning analysis and job-to-be-done mapping.\n`)+
    `CAPABILITY GUARD: ONLY suggest use cases that the seller's products ACTUALLY do. If the seller's exclusion list says they don't do something (e.g. payroll, benefits admin, hiring bonuses), do NOT suggest it as a use case — even if it would logically fit the target. OMIT the use case entirely. A rep who pitches something their company doesn't do loses credibility and the deal.\n`+
    `For each solution: (1) which seller PRODUCT (use exact name from catalog above), (2) what job-to-be-done it performs for ${co}, (3) what differentiator from the proof pack justifies "why us", (4) what NAMED CUSTOMER from the proof pack is similar evidence (or "[no analogue customer in our list — verify with seller]" if none fit), (5) what measurable outcome we'd target.\n`+
    `{"solutionMapping":[`+
    `{"product":"EXACT product name from seller catalog",`+
    `"imperativeServed":"Which universal imperative: grow revenue | reduce cost | stay compliant | reduce fraud/risk | satisfy investors | retain customers",`+
    `"buyerRole":"The specific persona who owns this problem (e.g. 'VP Operations' or 'CISO')",`+
    `"jobToBeDone":"The core job this product does for ${co} — one sentence in the buyer's language",`+
    `"painRelieved":"The specific pain this removes — concrete and measurable, not abstract",`+
    `"gainCreated":"What ${co} gains — quantified when possible",`+
    `"challengerInsight":"One assumption ${co}'s industry holds about this area that the seller can disprove with data or a case study — this is the teaching moment",`+
    `"joltRiskRemover":"How to take risk off the table for this solution — pilot scope, SLA, phased rollout, or reference customer",`+
    `"fit":"2 sentences: why this product fits ${co}. Cite ONE differentiator from the proof pack.",`+
    `"provenWith":"Named customer from the proof pack similar to ${co}, or '[no analogue — verify]'",`+
    `"measurableOutcome":"Specific outcome (e.g. 'Cut HR ticket volume 30% in 90 days')"},`+
    `{"product":"","imperativeServed":"","buyerRole":"","jobToBeDone":"","painRelieved":"","gainCreated":"","challengerInsight":"","joltRiskRemover":"","fit":"","provenWith":"","measurableOutcome":""}],`+
    `"caseStudies":[{"title":"Use a NAMED CUSTOMER from the seller's proof pack — do NOT invent","customer":"Customer name from the seller's list","relevance":"Why this past win is analogous to ${co}'s situation. Cite the specific parallel (industry, size, trigger, pain, outcome).","quantifiedOutcome":"What measurable result that customer achieved — quote from uploaded docs if available, mark as '[unsupported — verify]' if not"},{"title":"","customer":"","relevance":"","quantifiedOutcome":""}],`+
    `"keyContacts":[{"name":"Use ONLY names found in your web search results or the Apollo-verified contacts above. If search returned no name for this role, leave as EMPTY STRING — do NOT guess or fabricate names","title":"Likely title e.g. VP of Operations or Director of Procurement — always fill this even if name is unknown","initials":"First+last initials if name is known, empty string if not","angle":"Use role-specific language: CFO cares about margins and ROI, CIO cares about architecture and integration, CHRO cares about talent and engagement, VP Ops cares about efficiency and process. Match the angle to THEIR mandate, not a generic 'they would benefit from...' Write how to REACH them — what language resonates, what their first-90-day priority likely is."},{"name":"","title":"","initials":"","angle":""}],`+
    `"techStack":{"crm":"Use ONLY tech found in web search results (job postings, case studies, press). Empty string if not found — do NOT guess.","erp":"empty string if not found","hris":"empty string if not found","marketing":"empty string if not found","payments":"empty string if not found","analytics":"empty string if not found","infrastructure":"empty string if not found","other":[]},`+
    `"mobilizer":{"description":"Who is the likely Mobilizer at ${co}? The person who asks 'how do we make this happen?' — specific title, function, and what motivates them to champion this deal internally.","identifyingBehavior":"How will the seller know they've found this person in a meeting? What do they say or ask that a Talker or Blocker wouldn't?","teachingAngle":"The specific insight to teach THROUGH this Mobilizer to the broader buying group — one surprising fact or case study that reframes their assumptions."},`+
    `"processMaturity":{"dmiacStage":"Define|Measure|Analyze|Improve|Control","maturityNote":"1 sentence: where they are and what it means for seller entry","processGaps":["Gap 1","Gap 2"]}}`,
    (partial) => {
      if (!onStream || partial.length < 100) return;
      // For p4, try JSON parse since solutionMapping is complex
      try {
        const first = partial.indexOf('{');
        const last = partial.lastIndexOf('}');
        if (first >= 0 && last > first) {
          const parsed = JSON.parse(partial.slice(first, last + 1));
          if (parsed.solutionMapping?.[0]?.product) onStream("solutions", parsed);
        }
      } catch { /* partial — wait for more */ }
    }, 4500, { maxSearches: 1, anchorKey: "solutionMapping", onStatus, model: SONNET }
  );

  // MICRO 5: Live search — reuse pre-cache promise/result. Never duplicate.
  const liveCache = preCache.live;
  const p5 = liveCache
    ? (liveCache instanceof Promise ? liveCache : Promise.resolve(liveCache))
    : (async()=>{
    try{
      // p5 focuses on news, sentiment, and signals. Open roles are handled
      // by the dedicated p6 call which has its own web_search budget + fallback.
      const prompt =
        `Search for recent information about "${co}". Use at least one search specifically for press releases.\n\n`+
        `SEARCH STRATEGY (you have 2 searches — use BOTH, one for each purpose):\n`+
        `- Search 1 (NEWS): "${co}" news OR press release 2025 OR 2026\n`+
        `- Search 2 (REVIEWS — MANDATORY): "${co}" Glassdoor rating reviews\n`+
        `You MUST use Search 2 for Glassdoor. Every company with 100+ employees has Glassdoor reviews. BHN has thousands. A missing Glassdoor rating for a major employer is a data failure.\n\n`+
        `RECENCY RULE: ONLY include events, headlines, or signals from the last 18 months. Include the date or year in every headline.\n\n`+
        `WHAT TO EXTRACT:\n`+
        `1. Press releases and company announcements from the last 12 months\n`+
        `2. News coverage: M&A, leadership changes, funding, strategic moves\n`+
        `3. From Search 2: Glassdoor employer rating (a number like 3.8), CEO approval %, employee sentiment themes. Also G2 rating if software company.\n`+
        `4. Growth signals or buying indicators\n`+
        `5. Workforce and culture profile\n`+
        `Return ONLY raw JSON (start with {):\n`+
        `{"recentHeadlines":[{"headline":"Headline + source + date","relevance":"Why it matters","type":"press_release or news or review"},{"headline":"","relevance":"","type":""},{"headline":"","relevance":"","type":""},{"headline":"","relevance":"","type":""},{"headline":"","relevance":"","type":""}],`+
        `"recentSignals":["Most actionable buying signal","Second","Third"],`+
        `"growthSignals":["Growth indicator with evidence","Second"],`+
        `"workforceProfile":{"knowledgeWorkerPct":"estimated % of salaried/knowledge workers vs hourly","unionizedPct":"estimated % unionized if known","remotePolicy":"remote/hybrid/in-office","avgTenure":"if findable"},`+
        `"cultureProfile":{"coreValues":"2-3 stated company values","communicationStyle":"formal/informal","decisionMaking":"top-down/consensus/distributed","sellerLanguageHint":"the vocabulary and tone this company responds to"},`+
        `"incumbentVendors":{"hrSystem":"e.g. Workday/SAP/Oracle","financeSystem":"e.g. SAP/NetSuite","crmSystem":"e.g. Salesforce/Dynamics","cardProvider":"e.g. Amex/Citi"},`+
        `"sentimentScores":{"glassdoorRating":"Glassdoor rating as a NUMBER only e.g. '3.8' — empty string if not found. NEVER 'Not found' or 'N/A'.","g2Rating":"G2 rating as NUMBER only — empty string if not software or not found","trustpilotRating":"Trustpilot score as NUMBER only — empty string if not found","npsSignal":"NPS/CSAT data or brand perception — empty string if not found. NEVER placeholder text.","standoutReview":{"text":"most revealing quote from employee review, press, or consumer — empty string if none found","source":"source platform — empty string if none","sentiment":"positive or negative — empty string if none"}},`+
        `"companySnapshot":"Updated 2-3 sentence snapshot with any new facts"}`;
      const d = await claudeFetch({
        model:activeModel(),
        max_tokens:1800,
        temperature:0,
        tools:[{type:"web_search_20250305",name:"web_search",max_uses:2}],
        messages:[{role:"user",content:prompt}],
      });
      if(d.error) return null;
      // Tool-use response: multi-block (text + tool_use + tool_result + text)
      const textBlocks = (d.content||[]).filter(b=>b.type==="text").map(b=>b.text||"");
      for (let i = textBlocks.length - 1; i >= 0; i--) {
        const parsed = extractJsonWithKey(textBlocks[i], "recentHeadlines")
                    || extractJsonWithKey(textBlocks[i], "recentSignals")
                    || extractJsonWithKey(textBlocks[i], "sentimentScores");
        if (parsed) return parsed;
      }
      const raw = textBlocks.join("").trim();
      return safeParseJSON(raw.startsWith("{")?raw:"{"+raw);
    }catch(e){console.warn("Live search failed:",e.message);return null;}
  })();

  // Skeleton returned instantly. pickAccount renders it, then merges
  // each micro-result as its promise resolves. No await here.
  const skeleton = {
    ...BLANK_BRIEF,
    companySnapshot: `Researching ${co}...`,
    _loadingSections: {overview:true, executives:true, strategy:true, solutions:true, live:true, roles:true, deepIntel:true},
    _klVersions: _klActiveVersions, // which knowledge layers were injected for this brief
  };

  // Per-section merger functions, applied via setBrief(prev => merger(prev))
  // IMPORTANT: mergeOverview must NOT spread ...r1 blindly. If Haiku returns
  // extra fields (openingAngle, strategicTheme, etc.) in p1, they'd overwrite
  // what later mergers (p3, p4) set — causing data loss. Only take the fields
  // p1 is RESPONSIBLE for.
  const P1_FIELDS = ["companySnapshot","revenue","publicPrivate","employeeCount","headquarters","founded","website","linkedIn","fundingProfile","competitors","watchOuts"];
  const mergeOverview = (r1) => (prev) => {
    if (!prev) return prev;
    if (!r1 || typeof r1 !== "object") {
      return {...prev, _error: (prev._error || "Brief generation partial — Overview failed. Try Regenerate."),
              _loadingSections: {...(prev._loadingSections||{}), overview:false}};
    }
    const next = {...prev, _loadingSections: {...(prev._loadingSections||{}), overview:false}};
    P1_FIELDS.forEach(f => { if (r1[f] !== undefined) next[f] = r1[f]; });

    // Post-process: fix ownership contradictions
    // If fundingProfile mentions "acquired", "PE-backed", "private equity", or "went private"
    // but publicPrivate still shows a ticker — strip the ticker
    if (next.publicPrivate && next.fundingProfile) {
      const fp = (next.fundingProfile||"").toLowerCase();
      const pp = (next.publicPrivate||"").toLowerCase();
      const isPrivateSignal = /acquir|pe-backed|private equity|went private|taken private|buyout|delisted/.test(fp);
      const hasTicker = /\((?:nyse|nasdaq|tsx|lse):\s*[a-z]+\)/i.test(next.publicPrivate);
      if (isPrivateSignal && hasTicker) {
        // Strip the stale ticker — fundingProfile is more authoritative on ownership changes
        next.publicPrivate = next.publicPrivate.replace(/\s*\((?:NYSE|NASDAQ|TSX|LSE):\s*[A-Z]+\)/i, "").replace(/public/i, "Private").trim();
        if (!/private/i.test(next.publicPrivate)) next.publicPrivate = "Private";
      }
    }

    return next;
  };
  const mergeExecs = (r2) => (prev) => {
    if (!prev) return prev;
    const next = {...prev, _loadingSections: {...(prev._loadingSections||{}), executives:false}};
    if (r2?.keyExecutives?.length) next.keyExecutives = sanitizeWebResult(r2.keyExecutives);
    else { next._failedSections = [...(prev._failedSections||[]), "executives"]; }
    if (r2?.sellerSnapshot) next.sellerSnapshot = r2.sellerSnapshot;
    return next;
  };
  const mergeStrategy = (r3) => (prev) => {
    if (!prev) return prev;
    const next = {...prev, _loadingSections: {...(prev._loadingSections||{}), strategy:false}};
    if (!r3) { next._failedSections = [...(prev._failedSections||[]), "strategy"]; }
    if (r3?.elevatorPitch) next.elevatorPitch = r3.elevatorPitch;
    if (r3?.strategicTheme) next.strategicTheme = r3.strategicTheme;
    if (r3?.sellerOpportunity) next.sellerOpportunity = r3.sellerOpportunity;
    if (r3?.openingAngle) next.openingAngle = r3.openingAngle;
    // Only fill publicSentiment fields that aren't already set by p5 (mergeLive).
    // p5 has richer sentiment from web_search; p3 should backfill, not overwrite.
    if (r3?.publicSentiment) {
      const existing = next.publicSentiment || {};
      const merged = { ...existing };
      for (const [k, v] of Object.entries(r3.publicSentiment)) {
        if (v && !existing[k]) merged[k] = v;
      }
      next.publicSentiment = merged;
    }
    // relationshipSignals feature tabled
    return next;
  };
  const mergeSolutions = (r4) => (prev) => {
    if (!prev) return prev;
    const next = {...prev, _loadingSections: {...(prev._loadingSections||{}), solutions:false}};
    if (!r4) { next._failedSections = [...(prev._failedSections||[]), "solutions"]; }
    if (r4?.solutionMapping?.some(s=>s?.product)) next.solutionMapping = r4.solutionMapping;
    if (r4?.caseStudies?.some(c=>c?.title)) next.caseStudies = r4.caseStudies;
    if (r4?.keyContacts?.some(c=>c?.name||c?.title)) next.keyContacts = r4.keyContacts;
    if (r4?.techStack) next.techStack = r4.techStack;
    if (r4?.mobilizer?.description) next.mobilizer = r4.mobilizer;
    if (r4?.processMaturity?.dmiacStage) next.processMaturity = r4.processMaturity;
    return next;
  };
  const mergeLive = (r5raw) => (prev) => {
    if (!prev) return prev;
    const next = {...prev, _loadingSections: {...(prev._loadingSections||{}), live:false}};
    if (!r5raw) return next;
    const r5 = sanitizeWebResult(r5raw); // Sanitize web search results
    const errorWords = ["unable","cannot","search failed","not available","web search"];
    const cleanHL = (r5.recentHeadlines||[]).filter(h => {
      const t = (h?.headline||"").toLowerCase();
      return h?.headline && h.headline.length > 10 && !errorWords.some(w=>t.includes(w));
    });
    if (cleanHL.length) next.recentHeadlines = cleanHL;
    // Open roles are handled by dedicated p6 call — don't set from p5.
    if (r5.recentSignals?.some(s=>s)) next.recentSignals = r5.recentSignals;
    if (r5.growthSignals?.some(s=>s)) next.growthSignals = r5.growthSignals;
    const snapOk = r5.companySnapshot?.length > 50 && !errorWords.some(w=>r5.companySnapshot.toLowerCase().includes(w));
    if (snapOk) next.companySnapshot = r5.companySnapshot;
    if (r5.workforceProfile) next.workforceProfile = r5.workforceProfile;
    if (r5.cultureProfile) next.cultureProfile = r5.cultureProfile;
    if (r5.incumbentVendors) next.incumbentVendors = r5.incumbentVendors;
    if (r5.sentimentScores) {
      const ss = r5.sentimentScores;
      next.publicSentiment = {...next.publicSentiment,
        glassdoorRating: ss.glassdoorRating || next.publicSentiment?.glassdoorRating || "",
        g2Rating: ss.g2Rating || "",
        trustpilotRating: ss.trustpilotRating || "",
        npsSignal: ss.npsSignal || "",
        employeeScore: ss.employeeScore || "",
        standoutReview: ss.standoutReview?.text ? ss.standoutReview : next.publicSentiment?.standoutReview || {},
      };
    }
    return next;
  };

  // MICRO 6: Dedicated open roles search — separate from p5 so it gets its
  // own web_search budget. Two-phase approach:
  //   Phase 1: web_search for real current listings (LinkedIn, Indeed, etc.)
  //   Phase 2 (fallback): if web_search finds nothing useful, a fast non-search
  //            call infers plausible roles from training knowledge.
  // Careers pages are often JS-gated and unsearchable — the fallback ensures
  // we always show hiring intelligence rather than an empty section.
  const rolesHaveData = (obj) => obj?.openRoles?.roles?.some(r => r?.title);
  const rolesSummaryOk = (obj) => obj?.openRoles?.summary &&
    !/unable|could not|couldn't|not available|no results|cannot|search limit/i.test(obj.openRoles.summary);

  const p6 = (async () => {
    try {
      // Phase 1: web search for real listings
      const d = await claudeFetch({
        model: activeModel(),
        max_tokens: 1200,
        temperature: 0,
        tools: [{ type: "web_search_20250305", name: "web_search", max_uses: 2 }],
        messages: [{ role: "user", content:
          `Search for CURRENT open job listings at "${co}". This is critical sales intelligence — hiring patterns reveal strategic priorities and budget allocation.\n\n` +
          `SEARCH STRATEGY (use both searches):\n` +
          `1. Search: "${co} open jobs" OR "${co} careers hiring"\n` +
          `2. Search: "site:linkedin.com/jobs ${co}" OR "site:indeed.com ${co}"\n\n` +
          `From the search results, identify 3-5 SPECIFIC open roles. For each role:\n` +
          `- The exact job title\n` +
          `- The department (Engineering, Sales, HR, Finance, Operations, Marketing, etc.)\n` +
          `- What this hire SIGNALS about ${co}'s priorities (e.g. "Hiring a VP of Data = investing in analytics infrastructure")\n\n` +
          `Also write a 2-3 sentence summary of what the overall hiring pattern reveals about ${co}'s strategic direction.\n\n` +
          `Return ONLY raw JSON:\n` +
          `{"openRoles":{"summary":"2-3 sentences on what the hiring pattern reveals","roles":[{"title":"Exact job title","dept":"Department","signal":"What this hire tells a seller about priorities"},{"title":"","dept":"","signal":""},{"title":"","dept":"","signal":""}]}}`
        }],
      });
      if (!d.error) {
        const textBlocks = (d.content || []).filter(b => b.type === "text").map(b => b.text || "");
        for (let i = textBlocks.length - 1; i >= 0; i--) {
          const parsed = extractJsonWithKey(textBlocks[i], "openRoles");
          if (rolesHaveData(parsed)) { console.log("[p6] web_search returned roles"); return parsed; }
        }
        const raw = textBlocks.join("").trim();
        const parsed = safeParseJSON(raw.startsWith("{") ? raw : "{" + raw);
        if (rolesHaveData(parsed)) { console.log("[p6] web_search returned roles (joined)"); return parsed; }
        console.log("[p6] web_search returned no useful roles — falling back to inference");
      } else {
        console.log("[p6] web_search call errored — falling back to inference");
      }

      // Phase 2: fast fallback — no web_search, infer from training knowledge.
      // No assistant prefill — just a clean prompt. Haiku can infer plausible
      // roles for any well-known company from training knowledge alone.
      const d2 = await claudeFetch({
        model: activeModel(),
        max_tokens: 800,
        temperature: 0,
        messages: [{ role: "user", content:
          `You are a sales intelligence analyst. Based on your knowledge of "${co}"` +
          (url ? ` (${url})` : "") + `, list 3-5 roles they are likely hiring for right now.\n\n` +
          `Consider: their industry, company size, growth stage, recent strategic moves, and typical hiring patterns for companies like them.\n\n` +
          `REQUIREMENTS:\n` +
          `- Every role MUST have a specific, realistic job title (e.g. "Senior Data Engineer", "VP of Product Marketing") — NOT generic placeholders like "..." or "Specific Job Title"\n` +
          `- Every role MUST have a department and a signal explaining what the hire reveals\n` +
          `- Include a 2-3 sentence summary of what the hiring pattern reveals about strategic direction\n` +
          `- Be CONFIDENT — every company hires. Return plausible roles, not disclaimers or apologies.\n\n` +
          `Return ONLY raw JSON (start with {):\n` +
          `{"openRoles":{"summary":"2-3 sentences on hiring pattern","roles":[{"title":"Senior Data Engineer","dept":"Engineering","signal":"Investing in data infrastructure"},{"title":"Director of Customer Success","dept":"Customer Success","signal":"Scaling post-sale retention"},{"title":"Product Marketing Manager","dept":"Marketing","signal":"Go-to-market expansion"}]}}`
        }],
      });
      if (d2.error) { console.warn("[p6] fallback call errored:", d2.error); return null; }
      const tb2 = (d2.content || []).filter(b => b.type === "text").map(b => b.text || "");
      for (let i = tb2.length - 1; i >= 0; i--) {
        const parsed = extractJsonWithKey(tb2[i], "openRoles");
        if (rolesHaveData(parsed)) { console.log("[p6] fallback inference returned roles"); return parsed; }
      }
      const raw2 = tb2.join("").trim();
      const parsed2 = safeParseJSON(raw2.startsWith("{") ? raw2 : "{" + raw2);
      if (rolesHaveData(parsed2)) { console.log("[p6] fallback inference returned roles (joined)"); return parsed2; }
      console.warn("[p6] fallback produced no titled roles");
      return null;
    } catch (e) { console.warn("Open roles search failed:", e.message); return null; }
  })();

  // Merge p6 (open roles) into the brief
  const mergeRoles = (r6) => (prev) => {
    if (!prev) return prev;
    const next = {...prev, _loadingSections: {...(prev._loadingSections||{}), roles:false}};
    if (!r6) return next;
    if (rolesHaveData(r6) || rolesSummaryOk(r6)) next.openRoles = r6.openRoles;
    return next;
  };

  // ── DEEP INTELLIGENCE LAYERS (p7, p8, p9) — fire in parallel with p1-p6 ──

  // Identity context for deep intel calls — prevents cross-company contamination (Apollo.io vs Apollo Global)
  const deepIntelIdentity = (url && url !== co
    ? `IDENTITY: Research ONLY the company at https://${url} ("${co}"). Multiple companies share this name — use the website ${url} as the definitive identifier. Do NOT mix facts from different companies.\n\n`
    : `IDENTITY: Research the company "${co}". Do NOT mix facts from different companies with similar names.\n\n`) +
    secFilingCtx;

  // MICRO 7: Competitive Positioning — who they compete with and where they win/lose
  const p7 = (async()=>{
    try {
      const d = await claudeFetch({
        model: SONNET, max_tokens:2000,
        tools:[{type:"web_search_20250305",name:"web_search",max_uses:2}],
        messages:[{role:"user",content:
          deepIntelIdentity+
          `Research the competitive landscape of ${co}${url && url !== co ? ` (${url})` : ""}.\n\n`+
          `Search for "${co} ${url && url !== co ? url + ' ' : ''}competitors" and "${co} vs" to find real competitive dynamics.\n\n`+
          `COMPETITOR ACCURACY (CRITICAL): Only list companies that DIRECTLY compete with ${co} in the SAME product category. A competitor must offer a substitute product that a buyer would evaluate alongside ${co}. Companies in adjacent categories (analytics, CRM, data platforms, etc.) are NOT competitors unless they directly compete for the same budget and use case. If web search returns no clear competitors, return fewer entries or empty array — do NOT fill with companies from your training data that seem vaguely related. A wrong competitor name makes the rep look uninformed.\n\n`+
          `Return raw JSON:\n`+
          `{"competitivePositioning":{`+
          `"marketPosition":"2-3 sentences: where ${co} sits in the market. Category leadership or challenger status, analyst positioning (Gartner MQ, Forrester Wave if applicable). CRITICAL: Do NOT cite G2 Grid rankings, review-site 'market share' percentages, or product-listing counts as real market share. G2/Capterra/TrustRadius rank by reviews and traffic, NOT by actual revenue or market share. If the only market-share data available is from a review platform, omit it.",`+
          `"primaryCompetitors":[{"name":"ONLY companies found in your web search results that directly compete with ${co} in the same category. Empty array if search found no clear competitors.","strength":"Their #1 advantage over ${co}","weakness":"Where ${co} beats them","recentMove":"Latest competitive action — empty if unknown"}],`+
          `"whereWinning":"1-2 sentences: deal types, segments, or use cases where ${co} consistently wins and why",`+
          `"whereLosing":"1-2 sentences: where they lose deals and to whom — be specific about WHY (price, feature, relationship, incumbent)",`+
          `"displacementAngle":"1 sentence: if you were competing against ${co}, what's the angle that works? What assumption about them can be challenged?"}}`
        }],
      });
      const textBlocks=(d.content||[]).filter(b=>b.type==="text").map(b=>b.text||"");
      for(let i=textBlocks.length-1;i>=0;i--){
        const parsed=extractJsonWithKey(textBlocks[i],"competitivePositioning");
        if(parsed?.competitivePositioning) return parsed;
      }
      return null;
    }catch{return null;}
  })();

  // MICRO 8: Board & Investors — who governs and funds this company
  const p8 = (async()=>{
    try {
      const d = await claudeFetch({
        model:activeModel(), max_tokens:2000,
        tools:[{type:"web_search_20250305",name:"web_search",max_uses:2}],
        messages:[{role:"user",content:
          deepIntelIdentity+
          `Research the board of directors, investors, and governance of ${co}${url && url !== co ? ` (${url})` : ""}.\n\n`+
          `Search for "${co} ${url && url !== co ? url + ' ' : ''}board of directors" and "${co} investors funding".\n`+
          (isPublicCompany
            ? `This is a PUBLIC COMPANY. Search for:\n- "${co}" proxy statement DEF 14A board of directors (most authoritative source for board composition)\n- "${co}" institutional shareholders 13F filings\n- "${co}" activist investor OR shareholder proposal\n- "${co}" board committee assignments (audit, compensation, nominating)\nProxy statements contain exact board member names, committee assignments, tenure, compensation, and independence status. This is the gold standard for board intelligence.\n\n`
            : `For private/startup companies: search for funding rounds, lead investors, board observers.\nFor nonprofits: search for board members and major donors/grantors.\n\n`) +
          `Return raw JSON:\n`+
          `{"boardAndInvestors":{`+
          `"boardMembers":[{"name":"Full name","title":"Board title or role","background":"1 sentence: where they came from, what expertise they bring","significance":"Why this person matters for understanding ${co}'s strategy"${isPublicCompany ? ',"committee":"Board committee assignments (Audit, Compensation, Nominating/Governance)"' : ""}}],`+
          `"leadInvestors":"${isPublicCompany ? "Top institutional shareholders (Vanguard, BlackRock, etc.), any activist investors, notable insider ownership. Cite 13F data if found." : "Key investors or funding sources — names + amounts if known. For nonprofits: major grantors."}",`+
          `"investmentThesis":"1-2 sentences: what bet are the investors making? What outcome are they driving toward?",`+
          `"boardMandate":"1-2 sentences: what is the board pushing for right now? Growth, profitability, exit, expansion, compliance, turnaround?${isPublicCompany ? " Reference any stated board priorities from the proxy statement or recent shareholder communications." : ""}"}}`
        }],
      });
      const textBlocks=(d.content||[]).filter(b=>b.type==="text").map(b=>b.text||"");
      for(let i=textBlocks.length-1;i>=0;i--){
        const parsed=extractJsonWithKey(textBlocks[i],"boardAndInvestors");
        if(parsed?.boardAndInvestors) return parsed;
      }
      return null;
    }catch{return null;}
  })();

  // MICRO 9: Financial Deep Dive — trends, margins, segments, guidance
  const p9 = (async()=>{
    try {
      const d = await claudeFetch({
        model:activeModel(), max_tokens:2000,
        tools:[{type:"web_search_20250305",name:"web_search",max_uses:2}],
        messages:[{role:"user",content:
          deepIntelIdentity+
          `Research the financial performance and trajectory of ${co}${url && url !== co ? ` (${url})` : ""}.\n\n`+
          (isPublicCompany
            ? `This is a PUBLIC COMPANY. Use SEC filings as primary sources:\n`+
              `- Search: site:sec.gov "${co}" 10-K for annual financials (revenue, segments, margins, capex, risk factors)\n`+
              `- Search: "${co}" earnings call Q4 2024 OR Q1 2025 for CEO/CFO guidance quotes\n`+
              `- Search: "${co}" 10-K "Management's Discussion and Analysis" for forward-looking strategy\n`+
              `- 10-K Item 7 (MD&A) contains: revenue breakdown by segment, margin analysis, capital allocation priorities, forward guidance\n`+
              `- 10-K Item 1 (Business) contains: business segment descriptions, key customers, competitive position\n`+
              `- 10-K Item 1A (Risk Factors) contains: competitive vulnerabilities, technology dependencies, regulatory exposure\n`+
              `Cite specific filing dates and exact figures. "Per 10-K filed 2/28/2025" is authoritative.\n\n`
            : `For PRIVATE/STARTUP companies: search for funding rounds, growth metrics, valuation signals.\n`+
              `For NONPROFITS: search for annual reports, grant funding, program spending.\n\n`) +
          `Return raw JSON:\n`+
          `{"financialDeepDive":{`+
          `"revenueTrend":"2-3 sentences: revenue trajectory over 2-3 years. Growth rate, acceleration/deceleration, key drivers. ${isPublicCompany ? "Cite specific numbers from 10-K filings (e.g. '$4.2B FY2024, up 12% from $3.75B FY2023')." : "Cite specific numbers when available."}",`+
          `"marginTrend":"1-2 sentences: gross margin, operating margin, or EBITDA margin direction. ${isPublicCompany ? "Reference specific 10-K data (e.g. 'Operating margin expanded 200bps to 18.3% per 10-K filed 3/1/2025')." : "What's driving margin expansion or compression?"}",`+
          `"segmentBreakdown":"Which business segments or product lines drive the most revenue? ${isPublicCompany ? "Use 10-K segment reporting. Public companies must disclose segment revenue/profit by accounting standards." : "Any segment growing faster or shrinking?"}",`+
          `"earningsInsight":"${isPublicCompany ? "1-2 sentences: the most revealing quote from the latest earnings call. Attribute to a specific executive by name and title (e.g. 'CFO Jane Smith stated...'). Include the call date." : "1-2 sentences: the most revealing thing from their latest annual report or investor update. A direct quote from leadership is ideal."}",`+
          `"capitalPriorities":"${isPublicCompany ? "Where is capex going? Reference 10-K capital expenditure figures, R&D spend as % of revenue, M&A activity, share buyback authorization. What does capital allocation reveal about strategic priorities?" : "Where are they investing? R&D, M&A, geographic expansion, headcount? What does capital allocation reveal about strategy?"}",`+
          `"guidanceQuote":"A direct quote from leadership about future direction — ${isPublicCompany ? "from earnings call transcript with speaker name, title, and call date. This is the most valuable field for a seller — a CEO's own words about where they're headed." : "from press release or interview. Empty if not found."}"}}`
        }],
      });
      const textBlocks=(d.content||[]).filter(b=>b.type==="text").map(b=>b.text||"");
      for(let i=textBlocks.length-1;i>=0;i--){
        const parsed=extractJsonWithKey(textBlocks[i],"financialDeepDive");
        if(parsed?.financialDeepDive) return parsed;
      }
      return null;
    }catch{return null;}
  })();

  // MICRO 10: Gate Map — approval paths for both seller and buyer side
  const p10 = (async()=>{
    try {
      const dealSize = sellerICP?.icp?.dealSize || "";
      const d = await claudeFetch({
        model:activeModel(), max_tokens:2000,
        messages:[{role:"user",content:
          `You are a B2B sales strategist. Analyze the approval gates for a deal between seller "${sellerUrl}" and target "${co}"${url && url !== co ? ` (${url})` : ""}.\n\n`+
          `SELLER CONTEXT: ${sellerICP?.sellerDescription || sellerUrl}. Deal size: ${dealSize}. Stage: ${sellerICP?.icp?.salesCycle || "unknown"}.\n`+
          `TARGET CONTEXT: ${co} — Industry: ${member.ind || "unknown"}. Size: ${member.employees || "unknown"} employees.\n\n`+
          (KL_APPROVAL_GATES ? `APPROVAL GATES KNOWLEDGE:\n${KL_APPROVAL_GATES.slice(0, 3000)}\n\n` : "") +
          `Return raw JSON with TWO sections:\n`+
          `{"gateMap":{\n`+
          `"sellerGates":{"summary":"1-2 sentences: what the SELLER's own organization will likely require to approve this deal (deal desk, discount authority, legal review, etc.)","gates":[{"gate":"Gate name (e.g. Deal Desk Review)","owner":"Who owns this gate (e.g. RevOps / Sales Manager)","trigger":"What triggers this gate (e.g. discount >10% or non-standard terms)","artifact":"What you need to prepare (e.g. competitive context, margin analysis)","timeline":"Typical timeline (e.g. 2-5 business days)"}]},\n`+
          `"buyerGates":{"summary":"1-2 sentences: what the BUYER (${co}) will likely require internally to approve this purchase — based on their industry, size, and the deal value","gates":[{"gate":"Gate name (e.g. Procurement Review)","owner":"Who at ${co} owns this gate (by role, not name)","trigger":"What triggers this gate","artifact":"What the seller needs to provide to clear this gate","timeline":"Typical timeline"},{"gate":"","owner":"","trigger":"","artifact":"","timeline":""}]},\n`+
          `"criticalPath":"1-2 sentences: which gate is most likely to stall or kill this deal and what to do about it",\n`+
          `"mapAdvice":"1 sentence: the single most important action the seller should take THIS WEEK to de-risk the approval sequence"}}`
        }],
      });
      const textBlocks=(d.content||[]).filter(b=>b.type==="text").map(b=>b.text||"");
      for(let i=textBlocks.length-1;i>=0;i--){
        const parsed=extractJsonWithKey(textBlocks[i],"gateMap");
        if(parsed?.gateMap) return parsed;
      }
      return null;
    }catch{return null;}
  })();

  // Merge deep intelligence layers
  const mergeDeepIntel = (r7, r8, r9, r10) => (prev) => {
    if (!prev) return prev;
    const next = {...prev, _loadingSections: {...(prev._loadingSections||{}), deepIntel:false}};
    if (r7?.competitivePositioning) {
      const cp = { ...r7.competitivePositioning };
      // Post-process: strip review-platform metrics that masquerade as market share.
      // G2/Capterra "market share" is review volume, not economics. These patterns
      // have caused the worst hallucinations (e.g. "0.05% market share" for a market leader).
      if (cp.marketPosition) {
        cp.marketPosition = cp.marketPosition
          .replace(/\b0\.\d+%\s*market\s*(?:share|presence)\b/gi, "")
          .replace(/\b\d{2,3}[\s-]+(?:competitor|product|alternative)s?\b/gi, "")
          .replace(/ranked?\s*#?\d+\s*(?:of|out of|among)\s*\d+\s*(?:products?|competitors?|alternatives?)/gi, "")
          .replace(/\s{2,}/g, " ").trim();
      }
      next.competitivePositioning = cp;
    }
    if (r8?.boardAndInvestors) next.boardAndInvestors = r8.boardAndInvestors;
    if (r9?.financialDeepDive) next.financialDeepDive = r9.financialDeepDive;
    if (r10?.gateMap) next.gateMap = r10.gateMap;
    return next;
  };

  // earlyDone resolves when p1+p3+p4 settle (overview, strategy, solutions).
  // Hypothesis only needs these — no reason to wait for slow web_search
  // calls (p2 executives, p5 live search, p6 roles). Shaves 5-10s off hypothesis start.
  const earlyDone = Promise.allSettled([p1, p3, p4]);
  const deepIntelDone = Promise.allSettled([p7, p8, p9, p10]);

  // Error-logging catch — silent catches were hiding section failures (blank revenue, missing execs, etc.)
  const catchLog = (name, merger) => (e) => {
    console.error(`[brief] ${name} FAILED:`, e?.message || e);
    return merger(null);
  };

  return {
    skeleton,
    mergers: {
      overview:  p1.then(mergeOverview).catch(catchLog("p1-overview", mergeOverview)),
      executives:p2.then(mergeExecs).catch(catchLog("p2-executives", mergeExecs)),
      strategy:  p3.then(mergeStrategy).catch(catchLog("p3-strategy", mergeStrategy)),
      solutions: p4.then(mergeSolutions).catch(catchLog("p4-solutions", mergeSolutions)),
      live:      p5.then(mergeLive).catch(catchLog("p5-live", mergeLive)),
      roles:     p6.then(mergeRoles).catch(catchLog("p6-roles", mergeRoles)),
      deepIntel: deepIntelDone.then(([r7,r8,r9,r10]) => mergeDeepIntel(r7.status==="fulfilled"?r7.value:null, r8.status==="fulfilled"?r8.value:null, r9.status==="fulfilled"?r9.value:null, r10?.status==="fulfilled"?r10.value:null)),
    },
    earlyDone,
    allDone: Promise.allSettled([p1,p2,p3,p4,p5,p6,p7,p8,p9,p10]),
  };
}


